module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output wire [15:0] result
);

reg [15:0] result_reg;
reg [15:0] result_next;
reg res_valid_reg;
reg res_valid_next;
reg [15:0] remainder;
reg [15:0] quotient;
reg [15:0] remainder_next;
reg [15:0] quotient_next;
reg [15:0] SR;
reg [15:0] SR_next;
reg [15:0] NEG_DIVISOR;
reg [15:0] NEG_DIVISOR_next;
reg [3:0] cnt;
reg [3:0] cnt_next;
reg start_cnt;
reg start_cnt_next;
assign res_valid = res_valid_reg;
assign result = result_reg;
always@(*) begin
    if(rst==1'b1||cnt==8'd8) begin
        res_valid_next = 1'b0;
    end
    else if((res_valid&res_ready)==1'b1) begin
        res_valid_next = 1'b0;
    end
    else begin
        res_valid_next = res_valid;
    end
end
always@(posedge clk or posedge rst) begin
    if(rst==1'b1) begin
        res_valid_reg <= 1'b0;
    end
    else begin
        res_valid_reg <= res_valid_next;
    end
end
always@(posedge clk or posedge rst) begin
    if(rst==1'b1) begin
        start_cnt <= 1'b0;
    end
    else if(opn_valid==1'b1&&res_valid!=1'b1) begin
        start_cnt <= 1'b1;
    end
    else if(cnt==8'd8) begin
        start_cnt <= 1'b0;
    end
    else begin
        start_cnt <= start_cnt;
    end
end
always@(posedge clk or posedge rst) begin
    if(rst==1'b1) begin
        cnt <= 8'd0;
    end
    else if(start_cnt==1'b1) begin
        cnt <= cnt + 1'b1;
    end
    else begin
        cnt <= 8'd0;
    end
end
always@(posedge clk or posedge rst) begin
    if(rst==1'b1) begin
        NEG_DIVISOR <= 8'd0;
    end
    else if(start_cnt==1'b1) begin
        NEG_DIVISOR <= ~divisor + 1'b1;
    end
    else begin
        NEG_DIVISOR <= NEG_DIVISOR;
    end
end
always@(posedge clk or posedge rst) begin
    if(rst==1'b1) begin
        remainder <= 8'd0;
    end
    else if(start_cnt==1'b1) begin
        remainder <= dividend[7];
    end
    else if(cnt>8'd0) begin
        remainder <= remainder << 1;
        remainder[0] <= SR[7];
    end
    else begin
        remainder <= remainder;
    end
end
always@(posedge clk or posedge rst) begin
    if(rst==1'b1) begin
        quotient <= 8'd0;
    end
    else if(start_cnt==1'b1) begin
        quotient <= 8'd0;
    end
    else if(cnt>8'd0) begin
        quotient <= quotient << 1;
        quotient[0] <= SR[7];
    end
    else begin
        quotient <= quotient;
    end
end
always@(posedge clk or posedge rst) begin
    if(rst==1'b1) begin
        SR <= 9'd0;
    end
    else if(start_cnt==1'b1) begin
        SR <= {dividend, 1'b0};
    end
    else if(cnt>8'd0) begin
        SR <= {remainder, SR[6:0]};
    end
    else begin
        SR <= SR;
    end
end
always@(*) begin
    if(sign==1'b1) begin
        result_next = {remainder, quotient};
    end
    else begin
        result_next = {remainder[7:0], quotient[7:0]};
    end
end
always@(posedge clk or posedge rst) begin
    if(rst==1'b1) begin
        result_reg <= 16'd0;
    end
    else begin
        result_reg <= result_next;
    end
end
endmodule
